Set-StrictMode -Version 2.0
function Add-GodModeTraceSpan { param([string]$Project='.',[string]$MissionId,[string]$Name,[string]$Status='ok',[hashtable]$Data=@{}) $r=Initialize-GodModeStructure $Project; $span=@{schema_version=1;trace_id=if($MissionId){$MissionId}else{[guid]::NewGuid().ToString('N')};span_id=[guid]::NewGuid().ToString('N');mission_id=$MissionId;name=$Name;status=$Status;started_at=Get-GodModeIso;ended_at=Get-GodModeIso;duration_ms=0;data=$Data}; Add-GodModeJsonLine (Join-GodModePath $r 'memory/trace-crystal-ledger.jsonl') $span; Set-Content (Join-GodModePath $r ("traces/$($span.trace_id)-$($span.span_id).json")) ($span|ConvertTo-Json -Depth 20) -Encoding UTF8; $span }
